comments.body:
DeleteWithPrefix uses LIKE with the raw prefix. If req.Prefix contains SQL LIKE metacharacters (%, _, and for SQL Server also [ ]), this can match/delete unintended keys (data loss). Consider escaping the prefix for LIKE and adding an explicit ESCAPE clause, then build both the LIKE and NOT LIKE patterns from the escaped prefix.
```suggestion
// escapeSQLServerLikePattern escapes SQL Server LIKE metacharacters using "\" as the ESCAPE character.
func escapeSQLServerLikePattern(value string) string {
	replacer := strings.NewReplacer(
		`\\`, `\\\\`,
		`%`, `\%`,
		`_`, `\_`,
		`[`, `\[`,
		`]`, `\]`,
	)
	return replacer.Replace(value)
}

// DeleteWithPrefix removes direct-children keys of the given prefix in one
// server-side query. Matches in-memory "no-nested-||" semantics.
func (s *SQLServer) DeleteWithPrefix(parentCtx context.Context, req state.DeleteWithPrefixRequest) (state.DeleteWithPrefixResponse, error) {
	if err := req.Validate(); err != nil {
		return state.DeleteWithPrefixResponse{}, err
	}

	escapedPrefix := escapeSQLServerLikePattern(req.Prefix)
	prefixLike := escapedPrefix + "%"
	nestedPrefixLike := escapedPrefix + "%||%"

	query := fmt.Sprintf(
		"DELETE FROM [%s].[%s] WHERE [Key] LIKE @PrefixLike ESCAPE N'\\' AND [Key] NOT LIKE @NestedPrefixLike ESCAPE N'\\'",
		s.metadata.SchemaName, s.metadata.TableName,
	)
	res, err := s.db.ExecContext(
		parentCtx,
		query,
		sql.Named("PrefixLike", prefixLike),
		sql.Named("NestedPrefixLike", nestedPrefixLike),
	)
```

